// CloudWatch RUM embedded snippet — shared across all pages of this MPA.
// Each hard navigation loads a fresh copy of this script, which bootstraps
// the web client and keeps the same session via the cwr_s cookie.
//
// This demo loads the published 3.0.0 CDN bundle:
//   full: https://client.rum.us-east-1.amazonaws.com/3.0.0/cwr.js
//   slim: https://client.rum.us-east-1.amazonaws.com/3.0.0/cwr-slim.js
//
// Config comes from /config.local.js (served from public/, gitignored,
// generated by Examples/infra/scripts/write-configs.js after `cdk deploy`).
// Scenario is picked via ?scenario=noauth-cdn-full (default) or
// noauth-cdn-slim. Auth-cdn-* scenarios are not supported by the plain
// snippet (full mode's built-in Cognito always uses guest creds).
(function () {
    const CDN_BASE = 'https://client.rum.us-east-1.amazonaws.com/3.0.0';
    const cfg = window.__RUM_CONFIG__;
    if (!cfg) {
        console.warn(
            '[mpa-cdn-demo] window.__RUM_CONFIG__ not set. Run Examples/infra/scripts/write-configs.js after cdk deploy.'
        );
        return;
    }
    const params = new URLSearchParams(window.location.search);
    const key = params.get('scenario') || 'noauth-cdn-full';
    const scenario = cfg.scenarios && cfg.scenarios[key];
    if (!scenario) {
        console.warn(
            '[mpa-cdn-demo] unknown scenario:',
            key,
            '— available:',
            Object.keys(cfg.scenarios || {})
        );
        return;
    }
    const slim = key.endsWith('-slim');
    const src = slim ? CDN_BASE + '/cwr-slim.js' : CDN_BASE + '/cwr.js';
    // Slim CDN bundle: no bundled Cognito, no telemetries config field, default
    // signing: false. Paired with a resource-based policy on the AppMonitor,
    // the data plane accepts unsigned PutRumEvents. See docs/concepts/auth.md
    // flow #1 and docs/packages/slim.md.
    const snippetConfig = slim
        ? {
              sessionSampleRate: 1,
              endpoint: cfg.endpoint,
              allowCookies: true,
              debug: true
          }
        : {
              sessionSampleRate: 1,
              identityPoolId: scenario.identityPoolId,
              endpoint: cfg.endpoint,
              telemetries: [
                  'errors',
                  'performance',
                  ['http', { addXRayTraceIdHeader: true }],
                  'replay'
              ],
              allowCookies: true,
              enableXRay: true,
              debug: true
          };
    (function (n, i, v, r, s, c, u, x, z) {
        x = window.AwsRumClient = {
            q: [],
            n: n,
            i: i,
            v: v,
            r: r,
            c: c,
            u: u
        };
        window[n] = function (c, p) {
            x.q.push({ c: c, p: p });
        };
        z = document.createElement('script');
        z.async = true;
        z.src = s;
        document.head.insertBefore(
            z,
            document.getElementsByTagName('script')[0]
        );
    })('cwr', scenario.appMonitorId, '1.0.0', cfg.region, src, snippetConfig);
    console.info(
        '[mpa-cdn-demo] initialized:',
        slim ? 'slim' : 'full',
        '/',
        key
    );
})();
